export const checkId = 'cors';
export const name = 'CORS Configured';
export const appliesTo = ['deployable', 'server', 'framework'];

const CORS_DEPS = [
  'cors',
  'fastify-cors',
  '@fastify/cors',
  'koa-cors',
  'koa2-cors',
  'micro-cors',
  'cors-anywhere',
  'itty-cors',
  'nextjs-cors',
  '@elysiajs/cors',
  'express-cors',
];

const SERVER_RUNTIMES = [
  'express',
  'fastify',
  'koa',
  'hono',
  'restify',
  'connect',
  'polka',
  'hapi',
  'nitro',
  'nitropack',
  'http-server',
  'serve-static',
  'json-server',
  'next',
  'nuxt',
  'astro',
  'solid-start',
  'remix',
  '@remix-run/node',
  '@remix-run/server-runtime',
  '@sveltejs/kit',
];

const META_FRAMEWORKS = ['next', 'nuxt', 'astro', 'solid-start', 'remix', '@remix-run/node', '@sveltejs/kit'];

const CORS_PATTERNS = [
  /require\s*\(\s*['"][^'"]*cors['"]\s*\)/,
  /import\s+.*?['"][^'"]*cors['"]/,
  /from\s+['"][^'"]*cors['"]/,
  /access-control-allow-origin/i,
  /access-control-allow-methods/i,
  /access-control-allow-headers/i,
  /access-control-allow-credentials/i,
  /access-control-expose-headers/i,
  /access-control-max-age/i,
  /access-control-request/i,
  /cors\s*:\s*(true|\{)/i,
  /cors\s*\(/i,
  /enableCors/i,
  /allowedOrigins?/i,
  /allowOrigin/i,
  /corsOrigins?/i,
  /use\s*\(\s*cors/i,
  /register\s*\([^)]*cors/i,
  /corsHandler/i,
  /handleCors/i,
  /withCors/i,
  /setHeader\s*\(\s*['"]Access-Control/i,
  /headers\s*\(\s*\)\s*\{[^}]*access-control/i,
];

const CONFIG_PATTERNS = [
  /^next\.config\./,
  /^nuxt\.config\./,
  /^astro\.config\./,
  /^nitro\.config\./,
  /^vite\.config\./,
  /^remix\.config\./,
  /^svelte\.config\./,
  /^wrangler\.toml$/,
  /\.(config|rc)\.(js|ts|mjs|cjs)$/,
];

const TOOL_NAMES = new Set([
  'webpack',
  'rollup',
  'esbuild',
  'parcel',
  'babel',
  'gulp',
  'grunt',
  'tsup',
  'unbuild',
  'turbo',
  'turborepo',
  'lerna',
  'nx',
  'vitest',
  'jest',
  'mocha',
  'ava',
  'c8',
  'nyc',
  'eslint',
  'prettier',
  'biome',
  'swc',
  'oxc',
]);

function findCorsDep(depsObj) {
  if (!depsObj) return null;
  const keys = Object.keys(depsObj);
  return CORS_DEPS.find((d) => keys.includes(d)) || null;
}

function basename(p) {
  const idx = p.lastIndexOf('/');
  return idx >= 0 ? p.slice(idx + 1) : p;
}

function isInTestOrExample(p) {
  return /(^|\/)(test|tests|__tests__|spec|example|examples|fixtures|fixture|mock|mocks|docs|playground|storybook|e2e|cypress|vitest|jest|node_modules|dist|build|coverage|\.tmp|\.next|out)\//i.test(p);
}

function isTutorialRepo(packageJson) {
  if (!packageJson) return false;
  const signals = [
    packageJson.name,
    packageJson.description,
    ...(packageJson.keywords || []),
  ].filter(Boolean);
  return signals.some((s) => /\b(learn|tutorial|example|starter|template|demo|course|guide|workshop|cheatsheet|sample)\b/i.test(s));
}

function isLibraryOrToolSource(packageJson, tree) {
  if (!packageJson) return false;
  const name = packageJson.name || '';
  const scripts = packageJson.scripts || {};
  const keywords = (packageJson.keywords || []).map((k) => k.toLowerCase());
  const deps = { ...(packageJson.dependencies || {}), ...(packageJson.devDependencies || {}) };
  const hasPeers = !!(packageJson.peerDependencies && Object.keys(packageJson.peerDependencies).length > 0);
  const isPrivate = packageJson.private === true;
  const hasWorkspaces = !!(packageJson.workspaces || tree.some((p) => /^(pnpm-workspace\.yaml|turbo\.json|lerna\.json|nx\.json)$/.test(p)));
  const hasPackagesDir = tree.some((p) => /^packages\/[^/]+\//.test(p));
  const hasAppsDir = tree.some((p) => /^(apps|services)\/[^/]+\//.test(p));
  const hasMain = !!(packageJson.main || packageJson.module || packageJson.exports || packageJson.types || packageJson.typings);
  const hasStart = !!(scripts.start || scripts.serve || scripts['start:prod']);
  const hasServerDep = Object.keys(deps).some((d) => SERVER_RUNTIMES.includes(d));

  if (TOOL_NAMES.has(name)) return true;
  if (hasPeers && !hasStart) return true;
  if (isPrivate && hasWorkspaces && hasPackagesDir && !hasAppsDir && !hasStart) return true;
  if (hasMain && !hasStart && !hasServerDep) return true;

  const libKeywords = ['library', 'plugin', 'toolkit', 'sdk', 'utils', 'helpers', 'middleware', 'tool', 'compiler', 'bundler'];
  if (keywords.some((k) => libKeywords.includes(k)) && !hasStart) return true;

  return false;
}

function hasServerContext(packageJson, tree) {
  if (!packageJson) return false;
  const deps = { ...(packageJson.dependencies || {}), ...(packageJson.devDependencies || {}) };
  const scripts = packageJson.scripts || {};

  if (Object.keys(deps).some((d) => SERVER_RUNTIMES.includes(d))) return true;
  if (scripts.start || scripts.serve || scripts['start:prod']) return true;

  const serverConfigs = [/^wrangler\.toml$/, /^nitro\.config\./, /^next\.config\./, /^nuxt\.config\./, /^astro\.config\./, /^remix\.config\./, /^svelte\.config\./];
  if (tree.some((p) => serverConfigs.some((rx) => rx.test(basename(p))))) return true;

  const apiRouteRx = /\/(api|pages\/api|app\/api|server\/api|src\/app\/api|src\/pages\/api|src\/routes|routes|server\/routes|controllers|handlers|middleware|plugins)\/[^/]+\.(js|ts|mjs|cjs|mts|cts)$/;
  const routeFileRx = /\.route\.(js|ts|mjs|cjs|mts|cts)$/;
  if (tree.some((p) => !isInTestOrExample(p) && (apiRouteRx.test(p) || routeFileRx.test(p)))) return true;

  const serverEntryRx = /^(server|app|listen|main|worker)\.(js|ts|mjs|cjs|mts|cts)$/;
  const srcServerEntryRx = /^src\/(server|app|listen|main|worker)\.(js|ts|mjs|cjs|mts|cts)$/;
  if (tree.some((p) => !isInTestOrExample(p) && (serverEntryRx.test(basename(p)) || srcServerEntryRx.test(p)))) return true;

  return false;
}

export async function check(context) {
  const { tree, files, packageJson, repoType } = context;

  try {
    if (repoType === 'empty' || tree.length === 0) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Empty repo — CORS not applicable', findings: [] };
    }

    const relevantFiles = tree.filter((p) => /\.(js|ts|mjs|cjs|jsx|tsx|mts|cts|json|toml|yaml|yml)$/.test(p));
    if (relevantFiles.length === 0) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'No relevant source files — CORS not applicable', findings: [] };
    }

    if (isTutorialRepo(packageJson)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Tutorial or example repo — CORS not applicable', findings: [] };
    }

    const rootDeps = { ...(packageJson?.dependencies || {}), ...(packageJson?.devDependencies || {}), ...(packageJson?.peerDependencies || {}) };
    const rootCors = findCorsDep(rootDeps);
    if (rootCors) {
      return { checkId, status: 'pass', confidence: 'high', message: `CORS dependency found (${rootCors})`, findings: [] };
    }

    const isMonorepo = !!(packageJson?.workspaces || tree.some((p) => /^(pnpm-workspace\.yaml|turbo\.json|lerna\.json|nx\.json)$/.test(p)));
    let monorepoHasServer = false;

    if (isMonorepo) {
      const pkgPaths = tree
        .filter((p) => /(^|\/)package\.json$/.test(p) && !/node_modules/.test(p) && p !== 'package.json')
        .slice(0, 30);

      for (const pkgPath of pkgPaths) {
        const content = await files.get(pkgPath);
        if (!content) continue;
        try {
          const pj = JSON.parse(content);
          const subDeps = { ...(pj.dependencies || {}), ...(pj.devDependencies || {}) };
          const subScripts = pj.scripts || {};

          const subCors = findCorsDep(subDeps);
          if (subCors) {
            return {
              checkId,
              status: 'pass',
              confidence: 'high',
              message: `CORS dependency found in ${pkgPath} (${subCors})`,
              findings: [{ file: pkgPath, issue: 'CORS dependency detected' }],
            };
          }

          if (!monorepoHasServer) {
            if (Object.keys(subDeps).some((d) => SERVER_RUNTIMES.includes(d))) monorepoHasServer = true;
            if (subScripts.start || subScripts.serve || subScripts['start:prod']) monorepoHasServer = true;
          }
        } catch (parseErr) {
          // skip invalid JSON
        }
      }
    }

    if (isLibraryOrToolSource(packageJson, tree)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Library or tool source — CORS not applicable', findings: [] };
    }

    const candidates = [];
    for (const p of tree) {
      if (!/\.(js|ts|mjs|cjs|jsx|tsx|mts|cts|json|toml|yaml|yml)$/.test(p)) continue;
      if (isInTestOrExample(p)) continue;

      let score = 0;
      const b = basename(p);

      if (CONFIG_PATTERNS.some((rx) => rx.test(b))) score += 100;
      if (/^(server|app|listen|main|worker)\.(js|ts|mjs|cjs|mts|cts)$/.test(b)) score += 80;
      if (/^src\/(server|app|listen|main|worker)\.(js|ts|mjs|cjs|mts|cts)$/.test(p)) score += 75;
      if (/\/(api|routes|server\/api|app\/api|pages\/api|controllers|handlers|middleware|plugins)\/[^/]+\.(js|ts|mjs|cjs|mts|cts)$/.test(p)) score += 70;
      if (/\.route\.(js|ts|mjs|cjs|mts|cts)$/.test(p)) score += 50;
      if (/\.(js|ts|mjs|cjs|jsx|tsx|mts|cts)$/.test(p)) score += 10;
      if (/\.(json|toml|yaml|yml)$/.test(p)) score += 5;

      if (score > 0) candidates.push({ path: p, score });
    }

    candidates.sort((a, b) => b.score - a.score);
    const scanPaths = candidates.slice(0, 25);

    for (const { path: filePath } of scanPaths) {
      const content = await files.get(filePath);
      if (!content) continue;

      for (const pattern of CORS_PATTERNS) {
        if (pattern.test(content)) {
          return { checkId, status: 'pass', confidence: 'high', message: `CORS configuration found in ${filePath}`, findings: [{ file: filePath, issue: 'CORS detected' }] };
        }
      }

      if (/\.(json|toml|yaml|yml)$/.test(filePath) && /cors/i.test(content) && /access-control/i.test(content)) {
        return { checkId, status: 'pass', confidence: 'high', message: `CORS configuration found in ${filePath}`, findings: [{ file: filePath, issue: 'CORS detected in config' }] };
      }
    }

    const rootHasServer = hasServerContext(packageJson, tree);
